I'm building an AI coding assistant using Anthropic's Claude with tool_use. The agent helps developers understand codebases by reading and analyzing files. Here's my implementation:

```python
import anthropic
import os
import subprocess
import json

client = anthropic.Anthropic(api_key=os.getenv("ANTHROPIC_API_KEY"))

# Tool definitions
tools = [
    {
        "name": "read_file",
        "description": "Read the contents of a file in the codebase. Use this to understand code structure and answer questions about implementation.",
        "input_schema": {
            "type": "object",
            "properties": {
                "file_path": {
                    "type": "string",
                    "description": "Path to the file to read"
                }
            },
            "required": ["file_path"]
        }
    },
    {
        "name": "list_directory",
        "description": "List files and directories in a given path. Use this to explore the codebase structure.",
        "input_schema": {
            "type": "object",
            "properties": {
                "directory_path": {
                    "type": "string",
                    "description": "Path to the directory to list"
                }
            },
            "required": ["directory_path"]
        }
    },
    {
        "name": "run_command",
        "description": "Run a command to analyze code (e.g., linters, formatters, tests). Use this to check code quality.",
        "input_schema": {
            "type": "object",
            "properties": {
                "command": {
                    "type": "string",
                    "description": "Command to execute"
                }
            },
            "required": ["command"]
        }
    }
]

# Tool implementations
def read_file(file_path):
    """Read file contents."""
    with open(file_path, 'r') as f:
        return f.read()

def list_directory(directory_path):
    """List directory contents."""
    files = os.listdir(directory_path)
    return "\n".join(files)

def run_command(command):
    """Execute a command and return output."""
    result = subprocess.run(
        command,
        shell=True,
        capture_output=True,
        text=True
    )
    return result.stdout + result.stderr

# Main interaction loop
def chat_with_agent(user_message, project_dir="./project"):
    """Chat with AI agent that can use tools."""
    os.chdir(project_dir)  # Work in project directory

    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=4096,
            tools=tools,
            messages=messages
        )

        # Check if Claude wants to use a tool
        if response.stop_reason == "tool_use":
            # Execute the tool
            tool_use_block = next(
                block for block in response.content 
                if block.type == "tool_use"
            )

            tool_name = tool_use_block.name
            tool_input = tool_use_block.input

            # Call the appropriate function
            if tool_name == "read_file":
                result = read_file(tool_input["file_path"])
            elif tool_name == "list_directory":
                result = list_directory(tool_input["directory_path"])
            elif tool_name == "run_command":
                result = run_command(tool_input["command"])

            # Send tool result back to Claude
            messages.append({"role": "assistant", "content": response.content})
            messages.append({
                "role": "user",
                "content": [{
                    "type": "tool_result",
                    "tool_use_id": tool_use_block.id,
                    "content": result
                }]
            })
        else:
            # Claude provided a final response
            return response.content[0].text

# Example usage
if __name__ == "__main__":
    user_query = "What does the main.py file do? Can you explain the key functions?"
    response = chat_with_agent(user_query, project_dir="./my_project")
    print(response)
```

